import { useMemo, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { toast } from 'sonner';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { Tabs, type TabDef } from '@/components/Tabs';
import { DataTable, type Column } from '@/components/data/DataTable';
import { EmptyState } from '@/components/data/EmptyState';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { ApiError } from '@/lib/api';
import { formatNumber } from '@/lib/format';
import {
  useDataSourcesQuery,
  useDataSourceMetadataQuery,
  useDeleteDataSource,
  type ColumnMetadataDto,
  type TableMetadataDto,
} from './queries';

type TabKey = 'overview' | 'schema' | 'connection';

export default function DataSourceDetailPage() {
  const { id } = useParams();
  const numericId = id ? Number.parseInt(id, 10) : Number.NaN;
  const navigate = useNavigate();

  const listQuery = useDataSourcesQuery();
  const metadataQuery = useDataSourceMetadataQuery(Number.isFinite(numericId) ? numericId : null);
  const deleteMutation = useDeleteDataSource();
  const [confirmDelete, setConfirmDelete] = useState(false);
  const [tab, setTab] = useState<TabKey>('overview');

  const entry = useMemo(
    () => listQuery.data?.entries.find(x => x.id === numericId) ?? null,
    [listQuery.data, numericId],
  );

  if (Number.isNaN(numericId)) {
    return (
      <div className="page">
        <PageHeader title="Data source" />
        <EmptyState icon={<Icon.Alert size={20} />} title="Invalid data source id" description={String(id)} />
      </div>
    );
  }

  if (listQuery.isLoading) {
    return (
      <div className="page">
        <PageHeader title="Data source" sub={<span className="muted">Loading…</span>} />
      </div>
    );
  }

  if (!entry) {
    return (
      <div className="page">
        <PageHeader
          title={`Data source #${numericId}`}
          sub={<Link to="/data-sources" className="muted">← back to data sources</Link>}
        />
        <EmptyState icon={<Icon.Database size={20} />} title="Data source not found" />
      </div>
    );
  }

  const handleDelete = async () => {
    try {
      await deleteMutation.mutateAsync(entry.id);
      toast.success(`Deleted data source '${entry.name}'`);
      navigate('/data-sources');
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Delete failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const tableCount = metadataQuery.data?.tables.length ?? 0;
  const columnCount = metadataQuery.data?.tables.reduce((acc, t) => acc + t.columns.length, 0) ?? 0;

  const tabs: TabDef<TabKey>[] = [
    { key: 'overview', label: <><Icon.Layers size={13} /> Overview</> },
    { key: 'schema', label: <><Icon.Database size={13} /> Schema</>, count: tableCount },
    { key: 'connection', label: <><Icon.Key size={13} /> Connection</> },
  ];

  return (
    <div className="page">
      <PageHeader
        title={entry.name}
        sub={
          <span className="muted">
            <Link to="/data-sources" className="muted">Data sources</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            #{entry.id}
          </span>
        }
        actions={
          <>
            <button
              type="button"
              className="btn"
              onClick={() => metadataQuery.refetch()}
              disabled={metadataQuery.isFetching}
            >
              <Icon.Refresh size={14} className="btn__icon" />
              Refresh metadata
            </button>
            <button
              type="button"
              className="btn btn--danger"
              onClick={() => setConfirmDelete(true)}
            >
              <Icon.X size={14} className="btn__icon" />
              Delete
            </button>
          </>
        }
      />

      <div className="kpi-grid" style={{ marginBottom: 16 }}>
        <Kpi dot="brand" label="Type" value={entry.dataSourceType} sub={entry.databaseEngineType ?? '—'} />
        <Kpi dot="info" label="Tables" value={formatNumber(tableCount)} sub="from metadata" />
        <Kpi dot="ok" label="Columns" value={formatNumber(columnCount)} sub="across all tables" />
        <Kpi dot="warn" label="Queries" value={formatNumber(entry.queryCount)} sub={`${formatNumber(entry.migrationJobsCount)} migrations`} />
      </div>

      <div className="card">
        <Tabs tabs={tabs} active={tab} onChange={setTab} />

        {tab === 'overview' && <OverviewTab entry={entry} metadataLoading={metadataQuery.isLoading} />}
        {tab === 'schema' && <SchemaTab query={metadataQuery} />}
        {tab === 'connection' && <ConnectionTab entry={entry} />}
      </div>

      <ConfirmDialog
        open={confirmDelete}
        title="Delete data source"
        message={
          <>Delete data source <strong>{entry.name}</strong>? This removes related queries and migrations. This cannot be undone.</>
        }
        confirmLabel="Delete"
        destructive
        busy={deleteMutation.isPending}
        onConfirm={handleDelete}
        onCancel={() => setConfirmDelete(false)}
      />
    </div>
  );
}

function Kpi({ dot, label, value, sub }: { dot: string; label: string; value: string; sub: string }) {
  return (
    <div className="kpi">
      <div className="kpi__head">
        <span className={`kpi__dot kpi__dot--${dot}`}></span>
        <span className="kpi__label">{label}</span>
      </div>
      <div className="kpi__value">{value}</div>
      <div className="kpi__sub"><span className="muted">{sub}</span></div>
    </div>
  );
}

interface OverviewProps {
  entry: { id: number; name: string; dataSourceType: string; databaseEngineType: string | null; queryCount: number; migrationJobsCount: number; metadataLoadingEnabled: boolean };
  metadataLoading: boolean;
}

function OverviewTab({ entry, metadataLoading }: OverviewProps) {
  return (
    <div className="card__body">
      <dl style={{ display: 'grid', gridTemplateColumns: '180px 1fr', rowGap: 8, columnGap: 12, margin: 0 }}>
        <dt className="muted">Identifier</dt>
        <dd className="mono">#{entry.id}</dd>
        <dt className="muted">Name</dt>
        <dd style={{ fontWeight: 600 }}>{entry.name}</dd>
        <dt className="muted">Source type</dt>
        <dd><span className="pill">{entry.dataSourceType}</span></dd>
        <dt className="muted">Engine</dt>
        <dd>
          {entry.databaseEngineType
            ? <span className="mono">{entry.databaseEngineType}</span>
            : <span className="muted">—</span>}
        </dd>
        <dt className="muted">Metadata loading</dt>
        <dd>{entry.metadataLoadingEnabled
          ? <span className="pill pill--ok">Enabled</span>
          : <span className="muted">Disabled</span>}</dd>
        <dt className="muted">Queries</dt>
        <dd>{formatNumber(entry.queryCount)}</dd>
        <dt className="muted">Migration jobs</dt>
        <dd>{formatNumber(entry.migrationJobsCount)}</dd>
      </dl>

      {metadataLoading && (
        <div className="muted" style={{ fontSize: 12, marginTop: 16 }}>Loading metadata…</div>
      )}
    </div>
  );
}

function SchemaTab({ query }: { query: ReturnType<typeof useDataSourceMetadataQuery> }) {
  const [selected, setSelected] = useState<TableMetadataDto | null>(null);

  if (query.isLoading) {
    return <div className="card__body"><span className="muted">Loading schema…</span></div>;
  }

  if (query.isError) {
    return (
      <div className="card__body">
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load metadata"
          description={query.error instanceof Error ? query.error.message : 'Unknown error'}
        />
      </div>
    );
  }

  const tables = query.data?.tables ?? [];

  if (tables.length === 0) {
    return (
      <div className="card__body">
        <EmptyState
          icon={<Icon.Database size={20} />}
          title="No tables loaded"
          description="Enable metadata loading on this data source to see its schema."
        />
      </div>
    );
  }

  const active = selected ?? tables[0];

  return (
    <div className="card__body" style={{ display: 'grid', gridTemplateColumns: '260px 1fr', gap: 16, padding: 0 }}>
      <aside style={{
        borderRight: '1px solid var(--border)',
        maxHeight: 480,
        overflowY: 'auto',
        padding: 8,
      }}>
        {tables.map(t => {
          const key = `${t.schemaName}.${t.tableName}`;
          const isActive = active && active.schemaName === t.schemaName && active.tableName === t.tableName;
          return (
            <button
              key={key}
              type="button"
              onClick={() => setSelected(t)}
              className="btn btn--ghost"
              style={{
                width: '100%',
                justifyContent: 'flex-start',
                textAlign: 'left',
                padding: '6px 10px',
                background: isActive ? 'var(--surface-2)' : 'transparent',
                fontWeight: isActive ? 600 : 400,
              }}
            >
              <span className="mono" style={{ fontSize: 12 }}>{t.schemaName}.</span>
              <span style={{ fontSize: 13 }}>{t.tableName}</span>
            </button>
          );
        })}
      </aside>

      <section style={{ padding: 16, overflow: 'auto' }}>
        {active && <TableDetails table={active} />}
      </section>
    </div>
  );
}

const COLUMN_GRID = '0.6fr 1.6fr 1fr 0.5fr 0.5fr 1fr';

const COLUMN_TABLE_COLUMNS: Column<ColumnMetadataDto>[] = [
  { key: 'ord', header: '#', render: c => <span className="muted mono">{c.ordinalPosition}</span> },
  {
    key: 'name',
    header: 'Column',
    render: c => (
      <span style={{ fontWeight: c.isPrimaryKey ? 600 : 400 }}>
        {c.columnName}
        {c.isPrimaryKey && <span className="pill" style={{ marginLeft: 6 }}>PK</span>}
        {c.isForeignKey && <span className="pill" style={{ marginLeft: 4 }}>FK</span>}
      </span>
    ),
  },
  { key: 'type', header: 'Type', render: c => <span className="mono">{c.dataType}</span> },
  { key: 'null', header: 'Null', render: c => c.isNullable ? <span className="muted">yes</span> : <span>no</span> },
  { key: 'len', header: 'Len', render: c => c.maxLength != null ? formatNumber(c.maxLength) : <span className="muted">—</span> },
  {
    key: 'ref',
    header: 'References',
    render: c => c.foreignKeyTable
      ? <span className="mono muted">{c.foreignKeyTable}.{c.foreignKeyColumn}</span>
      : <span className="muted">—</span>,
  },
];

function TableDetails({ table }: { table: TableMetadataDto }) {
  return (
    <>
      <header style={{ marginBottom: 12 }}>
        <h3 className="card__title" style={{ margin: 0 }}>
          <span className="mono muted" style={{ fontSize: 12 }}>{table.schemaName}.</span>
          {table.tableName}
        </h3>
        {table.description && (
          <div className="muted" style={{ fontSize: 12, marginTop: 4 }}>{table.description}</div>
        )}
        <div className="muted" style={{ fontSize: 12, marginTop: 4 }}>
          {formatNumber(table.columns.length)} columns · {formatNumber(table.indexes.length)} indexes
        </div>
      </header>

      <DataTable
        columns={COLUMN_TABLE_COLUMNS}
        rows={table.columns}
        rowKey={c => c.columnName}
        gridTemplate={COLUMN_GRID}
      />

      {table.indexes.length > 0 && (
        <section style={{ marginTop: 16 }}>
          <h4 className="card__title" style={{ margin: '0 0 8px' }}>Indexes</h4>
          <ul style={{ margin: 0, paddingLeft: 18 }}>
            {table.indexes.map(idx => (
              <li key={idx.indexName} style={{ marginBottom: 4 }}>
                <span className="mono">{idx.indexName}</span>
                {idx.isPrimaryKey && <span className="pill" style={{ marginLeft: 6 }}>PK</span>}
                {idx.isUnique && !idx.isPrimaryKey && <span className="pill" style={{ marginLeft: 6 }}>UNIQUE</span>}
                <span className="muted" style={{ marginLeft: 8, fontSize: 12 }}>
                  ({idx.columns.join(', ')})
                </span>
              </li>
            ))}
          </ul>
        </section>
      )}
    </>
  );
}

function ConnectionTab({ entry }: { entry: { dataSourceType: string; databaseEngineType: string | null; metadataLoadingEnabled: boolean } }) {
  return (
    <div className="card__body">
      <div className="muted" style={{ fontSize: 12, marginBottom: 12 }}>
        Connection details are encrypted at rest and not returned by the API. To rotate credentials, delete the data source and re-create it.
      </div>
      <dl style={{ display: 'grid', gridTemplateColumns: '200px 1fr', rowGap: 8, columnGap: 12, margin: 0 }}>
        <dt className="muted">Source type</dt>
        <dd><span className="pill">{entry.dataSourceType}</span></dd>
        <dt className="muted">Database engine</dt>
        <dd>{entry.databaseEngineType ? <span className="mono">{entry.databaseEngineType}</span> : <span className="muted">—</span>}</dd>
        <dt className="muted">Metadata loading</dt>
        <dd>{entry.metadataLoadingEnabled ? 'Enabled' : 'Disabled'}</dd>
        <dt className="muted">Last refreshed</dt>
        <dd>
          <ConnectionRefreshedAt />
        </dd>
      </dl>
    </div>
  );
}

function ConnectionRefreshedAt() {
  // The list endpoint doesn't include a refresh timestamp; metadata payload does.
  // Render via consumer hook to keep the connection card synchronous.
  return <span className="muted">see Schema tab</span>;
}
